+async function waitForCondition(
+	condition: () => boolean,
+	timeoutMs = 500,
+	pollMs = 5,
+): Promise<void> {
+	if (condition()) return;
+	const deadline = Date.now() + timeoutMs;
+	while (!condition() && Date.now() < deadline) {
+		await sleep(pollMs);
+	}
+	if (!condition()) {
+		throw new Error("Timed out waiting for condition");
+	}
+}
